--
-- Name: get_all_fleets_path_from_root(uuid); Type: FUNCTION; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE FUNCTION stgfmscoresch.get_all_fleets_path_from_root(accountidarg uuid) RETURNS TABLE(accountid uuid, fleetid uuid, fleetname text, path text)
    LANGUAGE sql
    AS $$
with recursive children as (
    select ft.accountid, ft.pfleetid, ft.fleetid, ft.name, ft.name as path, 1 as height from fleet_tree ft
    JOIN account_fleet af ON ft.accountid = af.accountid AND ft.fleetid = af.fleetid
    where ft.accountid = accountidarg and af.isroot = true

    union all

    select ft.accountid, ft.pfleetid, ft.fleetid, ft.name, c.path || '/' || ft.name as path,
           c.height + 1 from fleet_tree ft
    join children c on ft.accountid = c.accountid and c.fleetid = ft.pfleetid
)
select c.accountid, c.fleetid, c.name as fleetname, c.path from children c
    order by height
$$;


ALTER FUNCTION stgfmscoresch.get_all_fleets_path_from_root(accountidarg uuid) OWNER TO lmmintellicar_admin;

--
-- Name: get_all_fleets_path_from_root(uuid, uuid); Type: FUNCTION; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE FUNCTION stgfmscoresch.get_all_fleets_path_from_root(accountidarg uuid, useridarg uuid) RETURNS TABLE(accountid uuid, fleetid uuid, fleetname text, path text, isroot boolean, createdat timestamp with time zone, createdby uuid)
    LANGUAGE sql
    AS $$
with recursive children as (
    select ft.accountid, ft.pfleetid, ft.fleetid, ft.name, ft.name as path, 1 as height from fleet_tree ft
    JOIN user_fleet uf ON ft.accountid = uf.accountid AND ft.fleetid = uf.fleetid
    where ft.accountid = accountidarg and uf.userid = useridarg

    union all

    select ft.accountid, ft.pfleetid, ft.fleetid, ft.name, c.path || '/' || ft.name as path,
           c.height + 1 from fleet_tree ft
    join children c on ft.accountid = c.accountid and c.fleetid = ft.pfleetid
)
select c.accountid, c.fleetid, c.name as fleetname, c.path, af.isroot, af.createdat, af.createdby from children c
    JOIN account_fleet af ON c.accountid = af.accountid AND c.fleetid = af.fleetid
    order by height
$$;


ALTER FUNCTION stgfmscoresch.get_all_fleets_path_from_root(accountidarg uuid, useridarg uuid) OWNER TO lmmintellicar_admin;

