--
-- Name: locked_users_summary; Type: VIEW; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE VIEW stgfmscoresch.locked_users_summary AS
 SELECT uls.userid,
    u.displayname,
    u.usertype,
    uls.consecutivefailedcount,
    uls.lastinvalidlogin,
    uls.lockeduntil,
        CASE
            WHEN (uls.lockeduntil > now()) THEN 'LOCKED'::text
            ELSE 'UNLOCKED'::text
        END AS current_status
   FROM (stgfmscoresch.user_login_security uls
     JOIN stgfmscoresch.users u ON ((uls.userid = u.userid)))
  WHERE (uls.islocked = true)
  ORDER BY uls.lastinvalidlogin DESC;


ALTER VIEW stgfmscoresch.locked_users_summary OWNER TO lmmintellicar_admin;

