--
-- Name: public_api_audit_log; Type: TABLE; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE TABLE stgfmscoresch.public_api_audit_log (
    auditid bigint NOT NULL,
    endpoint text NOT NULL,
    method text NOT NULL,
    statuscode smallint NOT NULL,
    issuccess boolean NOT NULL,
    requestkey text,
    requestvalue text,
    requestbody jsonb,
    responsebody jsonb,
    errorcode text,
    ipaddress inet,
    useragent text,
    referer text,
    requestid text,
    processingtimems integer,
    captchavalidated boolean DEFAULT false,
    createdat timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE stgfmscoresch.public_api_audit_log OWNER TO lmmintellicar_admin;

--
-- Name: public_api_call_stats; Type: VIEW; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE VIEW stgfmscoresch.public_api_call_stats AS
 SELECT endpoint,
    method,
    requestkey,
    count(*) AS total_calls,
    count(
        CASE
            WHEN (issuccess = true) THEN 1
            ELSE NULL::integer
        END) AS success_calls,
    count(
        CASE
            WHEN (issuccess = false) THEN 1
            ELSE NULL::integer
        END) AS failed_calls,
    round((((count(
        CASE
            WHEN (issuccess = true) THEN 1
            ELSE NULL::integer
        END))::numeric / (count(*))::numeric) * (100)::numeric), 2) AS success_rate_percent,
    avg(processingtimems) AS avg_processing_time_ms,
    max(processingtimems) AS max_processing_time_ms,
    count(DISTINCT requestvalue) AS unique_identifiers,
    count(DISTINCT ipaddress) AS unique_ips,
    min(createdat) AS first_call,
    max(createdat) AS last_call
   FROM stgfmscoresch.public_api_audit_log
  GROUP BY endpoint, method, requestkey
  ORDER BY (count(*)) DESC;


ALTER VIEW stgfmscoresch.public_api_call_stats OWNER TO lmmintellicar_admin;

--
-- Name: public_api_failed_calls; Type: VIEW; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE VIEW stgfmscoresch.public_api_failed_calls AS
 SELECT auditid,
    endpoint,
    method,
    statuscode,
    requestkey,
    requestvalue,
    errorcode,
    ipaddress,
    createdat
   FROM stgfmscoresch.public_api_audit_log
  WHERE (issuccess = false)
  ORDER BY createdat DESC;


ALTER VIEW stgfmscoresch.public_api_failed_calls OWNER TO lmmintellicar_admin;

--
-- Name: public_api_user_activity; Type: VIEW; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE VIEW stgfmscoresch.public_api_user_activity AS
 SELECT requestkey,
    requestvalue,
    count(*) AS total_requests,
    count(
        CASE
            WHEN (issuccess = true) THEN 1
            ELSE NULL::integer
        END) AS successful_requests,
    count(
        CASE
            WHEN (issuccess = false) THEN 1
            ELSE NULL::integer
        END) AS failed_requests,
    count(DISTINCT endpoint) AS unique_endpoints,
    count(DISTINCT ipaddress) AS unique_ips,
    min(createdat) AS first_activity,
    max(createdat) AS last_activity
   FROM stgfmscoresch.public_api_audit_log
  WHERE ((requestkey IS NOT NULL) AND (requestvalue IS NOT NULL))
  GROUP BY requestkey, requestvalue
  ORDER BY (count(*)) DESC;


ALTER VIEW stgfmscoresch.public_api_user_activity OWNER TO lmmintellicar_admin;

