--
-- Name: user_login_stats; Type: VIEW; Schema: stgfmscoresch; Owner: lmmintellicar_admin
--

CREATE VIEW stgfmscoresch.user_login_stats AS
 SELECT ssotype,
    loginattempt,
    count(*) AS attempt_count,
    count(DISTINCT userid) AS unique_users,
    date_trunc('hour'::text, createdat) AS hour_bucket
   FROM stgfmscoresch.user_login_audit
  WHERE (createdat >= (now() - '24:00:00'::interval))
  GROUP BY ssotype, loginattempt, (date_trunc('hour'::text, createdat))
  ORDER BY (date_trunc('hour'::text, createdat)) DESC;


